29	/// Serve the service with the supplied listener.
30	///
31	/// This method of running a service is intentionally simple and doesn't support much configuration.
32	/// hyper's default configuration applies (including [timeouts]); use hyper or hyper-util if you
33	/// need more control. You can supply a custom [`Executor`] via [`Serve::with_executor`] to
34	/// control how connection tasks are spawned.
35	///
36	/// It supports both HTTP/1 as well as HTTP/2.
37	///
38	/// # Examples
39	///
40	/// Serving a [`Router`]:
41	///
42	/// ```
43	/// use axum::{Router, routing::get};
44	///
45	/// # async {
46	/// let router = Router::new().route("/", get(|| async { "Hello, World!" }));
47	///
48	/// let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
49	/// axum::serve(listener, router).await;
50	/// # };
51	/// ```
52	///
53	/// See also [`Router::into_make_service_with_connect_info`].
54	///
55	/// Serving a [`MethodRouter`]:
56	///
57	/// ```
58	/// use axum::routing::get;
59	///
60	/// # async {
61	/// let router = get(|| async { "Hello, World!" });
62	///
63	/// let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
64	/// axum::serve(listener, router).await;
65	/// # };
66	/// ```
67	///
68	/// See also [`MethodRouter::into_make_service_with_connect_info`].
69	///
70	/// Serving a [`Handler`]:
71	///
72	/// ```
73	/// use axum::handler::HandlerWithoutStateExt;
74	///
75	/// # async {
76	/// async fn handler() -> &'static str {
77	///     "Hello, World!"
78	/// }
79	///
80	/// let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
81	/// axum::serve(listener, handler.into_make_service()).await;
82	/// # };
83	/// ```
84	///
85	/// See also [`HandlerWithoutStateExt::into_make_service_with_connect_info`] and
86	/// [`HandlerService::into_make_service_with_connect_info`].
87	///
88	/// # Return Value
89	///
90	/// Although this future resolves to `io::Result<()>`, it will never actually complete or return an
91	/// error. Errors on the TCP socket will be handled by sleeping for a short while (currently, one
92	/// second).
93	///
94	/// [timeouts]: hyper::server::conn::http1::Builder::header_read_timeout
95	/// [`Router`]: crate::Router
96	/// [`Router::into_make_service_with_connect_info`]: crate::Router::into_make_service_with_connect_info
97	/// [`MethodRouter`]: crate::routing::MethodRouter
98	/// [`MethodRouter::into_make_service_with_connect_info`]: crate::routing::MethodRouter::into_make_service_with_connect_info
99	/// [`Handler`]: crate::handler::Handler
100	/// [`HandlerWithoutStateExt::into_make_service_with_connect_info`]: crate::handler::HandlerWithoutStateExt::into_make_service_with_connect_info
101	/// [`HandlerService::into_make_service_with_connect_info`]: crate::handler::HandlerService::into_make_service_with_connect_info
102	#[cfg(all(feature = "tokio", any(feature = "http1", feature = "http2")))]
103	pub fn serve<L, M, S, B>(listener: L, make_service: M) -> Serve<L, M, S, B, TokioExecutor>
104	where
105	    L: Listener,
106	    M: for<'a> Service<IncomingStream<'a, L>, Error = Infallible, Response = S>,
107	    S: Service<Request, Response = Response<B>, Error = Infallible> + Clone + Send + 'static,
108	    S::Future: Send,
109	    B: HttpBody + Send + 'static,
110	    B::Data: Send,
111	    B::Error: Into<Box<dyn StdError + Send + Sync>>,
112	{
