433	impl<L, M, S, F, B, E> WithGracefulShutdown<L, M, S, F, B, E>
434	where
435	    L: Listener,
436	    L::Addr: Debug,
437	    M: for<'a> Service<IncomingStream<'a, L>, Error = Infallible, Response = S> + Send + 'static,
438	    for<'a> <M as Service<IncomingStream<'a, L>>>::Future: Send,
439	    S: Service<Request, Response = Response<B>, Error = Infallible> + Clone + Send + 'static,
440	    S::Future: Send,
441	    F: Future<Output = ()> + Send + 'static,
442	    B: HttpBody + Send + 'static,
443	    B::Data: Send,
444	    B::Error: Into<Box<dyn StdError + Send + Sync>>,
445	    E: Executor,
446	{
447	    async fn run(self) {
448	        let Self {
449	            mut listener,
450	            mut make_service,
451	            executor,
452	            signal,
453	            _marker,
454	        } = self;
455	
456	        let (signal_tx, signal_rx) = watch::channel(());
457	        executor.execute(async move {
458	            signal.await;
459	            trace!("received graceful shutdown signal. Telling tasks to shutdown");
460	            drop(signal_rx);
461	        });
462	
463	        let (close_tx, close_rx) = watch::channel(());
464	
465	        loop {
466	            let (io, remote_addr) = tokio::select! {
467	                conn = listener.accept() => conn,
468	                _ = signal_tx.closed() => {
469	                    trace!("signal received, not accepting new connections");
470	                    break;
471	                }
472	            };
473	
474	            handle_connection(
475	                &mut make_service,
476	                &signal_tx,
477	                &close_rx,
478	                io,
479	                remote_addr,
480	                &executor,
481	            )
482	            .await;
483	        }
484	
485	        drop(close_rx);
486	        drop(listener);
487	
488	        trace!(
489	            "waiting for {} task(s) to finish",
490	            close_tx.receiver_count()
491	        );
492	        close_tx.closed().await;
493	    }
494	}
